// Build log messages SQL from Parse + Delay Calc output
// Runs AFTER Send Reply iMessage so all upstream data is available
const d = $('Parse + Delay Calc').first().json;

function safeStr(v) {
  return String(v == null ? '' : v).replace(/'/g, "''");
}

const tid = safeStr(d.db_thread_id);
const msg = safeStr(d.original_message);
const mid = safeStr(d.messageId);
const rep = safeStr(d.reply);
const stg = safeStr(d.stage);

if (!tid) {
  return [{ json: { query: 'SELECT 1 -- no thread_id, skipping message log' } }];
}

const query = [
  "INSERT INTO app.messages (thread_id, direction, sender, body, bloom_message_id, sent_at)",
  "VALUES ('" + tid + "'::uuid, 'inbound'::message_direction, 'contact'::message_sender, '" + msg + "', '" + mid + "', NOW());",
  "",
  "INSERT INTO app.messages (thread_id, direction, sender, body, sent_at)",
  "VALUES ('" + tid + "'::uuid, 'outbound'::message_direction, 'bot'::message_sender, '" + rep + "', NOW());",
  "",
  "UPDATE app.message_threads",
  "SET touchpoint_count = touchpoint_count + 1,",
  "    stage = '" + stg + "'::conversation_stage,",
  "    last_outreach_at = NOW(),",
  "    next_followup_at = NOW() + INTERVAL '24 hours',",
  "    updated_at = NOW()",
  "WHERE id = '" + tid + "'::uuid;"
].join('\n');

return [{ json: { query } }];

// Build arbitrage + handover SQL from Parse + Delay Calc output
const d = $('Parse + Delay Calc').first().json;

function safeStr(v) {
  return String(v == null ? '' : v).replace(/'/g, "''");
}

const pid = safeStr(d.property_id);
const lid = safeStr(d.listing_id);
const tid = safeStr(d.db_thread_id);
const desc = safeStr(d.reason);
const isArb = d.arbitrage_detected ? 'arbitrage_detected' : 'deal_progression';

if (!pid || !tid) {
  return [{ json: { query: 'SELECT 1 -- missing property_id or thread_id, skipping arbitrage log' } }];
}

const lidSql = lid ? ("'" + lid + "'::uuid") : 'NULL';

const query = [
  "INSERT INTO app.arbitrage_events (property_id, listing_id, thread_id, event_type, description, detected_by, detected_at, is_actionable)",
  "VALUES (",
  "  '" + pid + "'::uuid,",
  "  " + lidSql + ",",
  "  '" + tid + "'::uuid,",
  "  'other'::arbitrage_type,",
  "  '" + desc + "',",
  "  'bot'::message_sender,",
  "  NOW(),",
  "  TRUE",
  ");",
  "",
  "INSERT INTO app.handover_events (thread_id, reason, notes, handed_over_at, handed_over_to)",
  "VALUES (",
  "  '" + tid + "'::uuid,",
  "  '" + isArb + "'::handover_reason,",
  "  '" + desc + "',",
  "  NOW(),",
  "  'jean'",
  ");",
  "",
  "UPDATE app.message_threads",
  "SET status = 'handed_off', handed_off = TRUE, handed_off_at = NOW(), handed_off_to = 'jean'",
  "WHERE id = '" + tid + "'::uuid;"
].join('\n');

return [{ json: { query } }];

// ============================================================
// EXTRACT INBOUND — Parse Blooio webhook payload
// ============================================================
const body = $input.first().json.body || $input.first().json;
let phone = '';
let text = '';
let messageId = '';
let eventType = '';

if (body.data) {
  phone = body.data.chat || body.data.from || body.data.sender || body.data.phone || '';
  text = body.data.text || body.data.body || body.data.message || body.data.content || '';
  messageId = body.data.id || body.data.messageId || '';
  eventType = body.event || body.type || '';
} else {
  phone = body.chat || body.from || body.sender || body.phone || body.contact || '';
  text = body.text || body.body || body.message || body.content || '';
  messageId = body.id || body.messageId || '';
  eventType = body.event || body.type || '';
}

if (eventType && !eventType.includes('inbound') && !eventType.includes('received') && !eventType.includes('message.new')) {
  return [{ json: { skip: true, eventType, phone } }];
}

phone = phone.replace(/[^+0-9]/g, '');

if (!text || !phone) {
  return [{ json: { skip: true, reason: 'No text or phone in payload', raw: JSON.stringify(body).substring(0, 500) } }];
}

return [{ json: {
  skip: false,
  phone,
  message: text.trim(),
  messageId,
  eventType,
  thread_id: 'imsg-' + phone.replace(/[^0-9]/g, '')
} }];

