// ============================================================
// PREPARE AGENT INPUT — KB + Calendar + DB Context merger
// ============================================================

const inboundData = $('Extract Inbound2').first().json;
const userMessage = (inboundData.message || '').trim();
const threadId = inboundData.thread_id || '';
const phone = inboundData.phone || '';

// ---- EXTRACT DB CONTEXT ----
let dbContext = {};
try {
  const dbData = $('DB: Lookup Contact + Thread2').first().json;
  if (dbData && dbData.contact_id) {
    dbContext = {
      contact_id: dbData.contact_id || '',
      contact_name: dbData.full_name || '',
      contact_role: dbData.role || '',
      thread_id: dbData.thread_id || '',
      property_id: dbData.property_id || '',
      listing_id: dbData.listing_id || '',
      thread_status: dbData.thread_status || '',
      thread_stage: dbData.stage || 'open',
      touchpoint_count: dbData.touchpoint_count || 0,
      thread_type: dbData.thread_type || '',
      property_address: dbData.address || '',
      property_city: dbData.city || '',
      property_state: dbData.state || '',
      property_type: dbData.property_type || '',
      list_price: dbData.list_price || '',
      days_on_market: dbData.days_on_market || '',
      listing_status: dbData.listing_status || ''
    };
  }
} catch (e) {
  dbContext = {};
}

// Build property context string for the AI
let propertyContext = '';
if (dbContext.property_address) {
  propertyContext = 'PROPERTY CONTEXT:\n';
  propertyContext += 'Address: ' + dbContext.property_address + ', ' + dbContext.property_city + ', ' + dbContext.property_state + '\n';
  if (dbContext.property_type) propertyContext += 'Type: ' + dbContext.property_type + '\n';
  if (dbContext.list_price) propertyContext += 'List Price: $' + Number(dbContext.list_price).toLocaleString() + '\n';
  if (dbContext.days_on_market) propertyContext += 'Days on Market: ' + dbContext.days_on_market + '\n';
  if (dbContext.listing_status) propertyContext += 'Listing Status: ' + dbContext.listing_status + '\n';
  if (dbContext.contact_name) propertyContext += 'Contact: ' + dbContext.contact_name + ' (' + (dbContext.contact_role || 'unknown role') + ')\n';
  if (dbContext.thread_stage) propertyContext += 'Conversation Stage: ' + dbContext.thread_stage + '\n';
  if (dbContext.touchpoint_count) propertyContext += 'Touchpoints so far: ' + dbContext.touchpoint_count + '\n';
}

// ---- EXTRACT KB TEXT ----
let kbText = '';
try {
  const kbNode = $('Load KB SharePoint2').first();
  if (kbNode.json && typeof kbNode.json === 'object') {
    const d = kbNode.json;
    if (typeof d.text === 'string' && d.text.length > 50) kbText = d.text;
    else if (typeof d.body === 'string' && d.body.length > 50) kbText = d.body;
    else if (typeof d.content === 'string' && d.content.length > 50) kbText = d.content;
    else if (typeof d.data === 'string' && d.data.length > 50) kbText = d.data;
  }
  if (!kbText && kbNode.binary) {
    const binaryKeys = Object.keys(kbNode.binary);
    if (binaryKeys.length > 0) {
      const bin = kbNode.binary[binaryKeys[0]];
      if (bin.data) {
        try {
          const decoded = Buffer.from(bin.data, 'base64').toString('utf-8');
          const textMatches = decoded.match(/(?:>)([^<]{20,})/g);
          if (textMatches && textMatches.length > 5) {
            kbText = textMatches.map(function(m) { return m.replace(/^>/, '').trim(); }).filter(function(t) { return t.length > 10 && !t.includes('xmlns') && !t.includes('w:') && !t.includes('mc:'); }).join(' ');
          }
        } catch (decodeErr) {}
      }
    }
  }
} catch (e) {
  kbText = '';
}

if (!kbText || kbText.length < 200) {
  kbText = 'KNOWLEDGE BASE DID NOT LOAD — USE MINIMAL CONTEXT:\nYou are Fil Shnayder, Manager at Kumo Capital. Deal intake email: jean@investkumo.com. Owner-operator, $265M+ AUM. Multi-tenant industrial/flex, $5M-$40M, Southeast and Midwest.\nStay in character. NEVER say you are AI.';
}

// ---- EXTRACT CALENDAR ----
let calendarContext = '';
try {
  const calData = $('Load Calendar2').first().json || {};
  const events = calData.value || [];
  if (events.length === 0 && !calData.error) {
    calendarContext = 'Calendar is clear for the next 3 days. Propose any business hours (9 AM - 6 PM ET).';
  } else if (events.length > 0) {
    const busySlots = [];
    for (const ev of events) {
      const startRaw = ev.start && (ev.start.dateTime || ev.start);
      const endRaw = ev.end && (ev.end.dateTime || ev.end);
      if (!startRaw) continue;
      const start = new Date(startRaw);
      const end = endRaw ? new Date(endRaw) : new Date(start.getTime() + 3600000);
      const etOffset = -5 * 60 * 60 * 1000;
      const startET = new Date(start.getTime() + etOffset);
      const endET = new Date(end.getTime() + etOffset);
      const dayNames = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
      const monthNames = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
      function formatTime(d) {
        let h = d.getUTCHours(); const m = d.getUTCMinutes();
        const ampm = h >= 12 ? 'PM' : 'AM'; h = h % 12 || 12;
        return m === 0 ? (h + ' ' + ampm) : (h + ':' + String(m).padStart(2,'0') + ' ' + ampm);
      }
      const dayStr = dayNames[startET.getUTCDay()] + ' ' + monthNames[startET.getUTCMonth()] + ' ' + startET.getUTCDate();
      busySlots.push(dayStr + ': ' + formatTime(startET) + ' - ' + formatTime(endET) + ' (' + (ev.subject || 'Busy') + ')');
    }
    if (busySlots.length > 0) {
      calendarContext = 'Busy times next 3 days (ET):\n' + busySlots.join('\n') + '\nPropose times that do NOT conflict.';
    } else {
      calendarContext = 'Calendar is clear for the next 3 days. Propose any business hours (9 AM - 6 PM ET).';
    }
  } else {
    calendarContext = 'Calendar not available. Say you will check schedule and circle back, set escalate true.';
  }
} catch (e) {
  calendarContext = 'Calendar not available. Say you will check schedule and circle back, set escalate true.';
}

return [{ json: {
  thread_id: dbContext.thread_id || threadId,
  db_thread_id: dbContext.thread_id || '',
  contact_id: dbContext.contact_id || '',
  property_id: dbContext.property_id || '',
  listing_id: dbContext.listing_id || '',
  phone: phone,
  message: userMessage,
  messageId: inboundData.messageId || '',
  kb_context: kbText,
  calendar_context: calendarContext,
  property_context: propertyContext,
  contact_name: dbContext.contact_name || '',
  thread_stage: dbContext.thread_stage || 'open'
} }];

// ============================================================
// PARSE AI OUTPUT + DELAY CALCULATION + IDENTITY BREAK DETECTION
// ============================================================

const raw = $json.output || $json.response || $json.text || JSON.stringify($json) || '';

// Pull all upstream context from a single node reference
const ctx = $('Prepare Agent Input').first().json;

let parsed = {};
let reply = '';
let escalate = false;
let reason = '';
let brokerEmail = '';

try {
  let jsonStr = raw;
  if (raw.includes('```json')) {
    jsonStr = raw.split('```json')[1].split('```')[0] || raw;
  } else if (raw.includes('```')) {
    jsonStr = raw.split('```')[1].split('```')[0] || raw;
  }
  const jsonMatch = jsonStr.match(/\{[\s\S]*"reply"[\s\S]*\}/);
  if (jsonMatch) jsonStr = jsonMatch[0];
  parsed = JSON.parse(jsonStr.trim());
  reply = (parsed.reply || '').trim();
  escalate = Boolean(parsed.escalate);
  reason = (parsed.reason || '').trim();
  brokerEmail = (parsed.broker_email || '').trim();
} catch (e) {
  reply = raw.replace(/```json/g, '').replace(/```/g, '').trim().substring(0, 500);
  escalate = false;
}

if (!reply) reply = raw.substring(0, 500);

// Strip [[ARBITRAGE_DETECTED]] marker if model leaked it into reply text
reply = reply.replace(/\[\[ARBITRAGE_DETECTED\]\]/gi, '').replace(/^\s*\n+/, '').trim();

// Collapse newlines so Blooio doesn't split into multiple messages
reply = reply.replace(/\n+/g, ' ').trim();

const identityBreakPatterns = [
  /i[\s']?m\s+an?\s+(ai|artificial|chatbot|model|assistant)/i,
  /i[\s']?m\s+claude/i,
  /i[\s']?m\s+not\s+(human|a person)/i,
  /as\s+(an?\s+)?(ai|artificial)/i,
  /i[\s']?m\s+powered\s+by/i
];

const brokeCharacter = identityBreakPatterns.some(function(pattern) { return pattern.test(reply); });
if (brokeCharacter) {
  escalate = true;
  reason = 'AI identity leak detected';
}

const baseDelay = 3 + Math.random() * 5;
const wordCount = reply.split(/\s+/).length;
const typingDelay = Math.ceil(wordCount / 40);
const delaySec = Math.max(3, Math.min(baseDelay + typingDelay, 15));

return [{ json: {
  reply,
  escalate: Boolean(escalate),
  reason,
  broker_email: brokerEmail,
  phone: ctx.phone || '',
  original_message: ctx.message || '',
  thread_id: ctx.thread_id || '',
  db_thread_id: ctx.db_thread_id || '',
  contact_id: ctx.contact_id || '',
  property_id: ctx.property_id || '',
  listing_id: ctx.listing_id || '',
  messageId: ctx.messageId || '',
  stage: (parsed && parsed.stage) || ctx.thread_stage || 'open',
  delay_seconds: delaySec,
  arbitrage_detected: /\[\[ARBITRAGE_DETECTED\]\]/i.test(raw) || /arbitrage.{0,20}(detected|found)/i.test(reason)
} }];
